INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.1.1','cb','cb.adi.1','ЧБ Ади 1.1',1,'আজানুলম্বিত-ভুজৌ কনকাবদাতৌ সঙ্কীর্ত্তনৈকপিতরৌ কমলায়তাক্ষৌ ।
বিশ্বম্ভরৌ দ্বিজবরৌ যুগধর্ম্মপালৌ বন্দে জগৎপ্রিয়করৌ করুণাবতারৌ ॥১॥','а̄джа̄ну-ламбита-бхуджау канака̄вада̄тау
сан̇кӣртанаика-питарау камала̄йата̄кш̣ау
виш́вамбхарау двиджа-варау йуга-дхарма-па̄лау
ванде джагат прийа-карау карун̣а̄вата̄рау',NULL,NULL),('cb.adi.1.2','cb','cb.adi.1','ЧБ Ади 1.2',2,'নমস্ত্রিকাল-সত্যায় জগন্নাথ-সুতায় চ ।
স-ভৃত্যায় স-পুত্ত্রায় স-কলত্রায় তে নমঃ ॥২॥','намас трика̄ла сатйа̄йа
джаганна̄тха сута̄йа ча
са-бхр̣тйа̄йа са-путра̄йа
са-калатра̄йа те намах̣',NULL,NULL),('cb.adi.1.3','cb','cb.adi.1','ЧБ Ади 1.3',3,'অবতীর্ণৌ স-কারুণ্যৌ পরিচ্ছিন্নৌ সদীশ্বরৌ ।2
শ্রীকৃষ্ণচৈতন্য-নিত্যানন্দৌ দ্বৌ ভ্রাতরৌ ভজে ॥৩॥','аватӣрн̣ау са-ка̄рун̣йау
париччхиннау сад ӣш́варау
ш́рӣ кр̣ш̣н̣а чаитанйа-нитйа̄нандау
двау бхра̄тарау бхадже',NULL,NULL),('cb.adi.1.4','cb','cb.adi.1','ЧБ Ади 1.4',4,'স জয়তি বিশুদ্ধবিক্রমঃ কনকাভঃ কমলায়তেক্ষণঃ ।
বরজানুবিলম্বি-ষ্ভুজো বহুধা ভক্তিরসাভিনর্ত্তকঃ ॥৪॥','са джайати виш́уддха-викрамах̣
канака̄бхах̣ камала̄йатекш̣ан̣ах
вара-джа̄ну-виламби-ш̣ад̣-бхуджо
бахудха̄ бхакти-раса̄бхинартаках̣',NULL,NULL),('cb.adi.1.5','cb','cb.adi.1','ЧБ Ади 1.5',5,'জয়তি জয়তি দেবঃ কৃষ্ণচৈতন্যচন্দ্রো জয়তি জয়তি কীর্ত্তিস্তস্য নিত্যা পবিত্রা ।
জয়তি জয়তি ভৃত্যস্তস্য বিশ্বেশমূর্ত্তে- র্জয়তি জয়তি নৃত্যং তস্য সর্ব্বপ্রিয়াণাম্ ॥৫॥','джайати джайати девах̣
кр̣ш̣н̣а-чаитанйа-чандро
джайати джайати кӣртис
тасйа нитйа̄ павитра̄
джайати джайати бхр̣тйа̄с
тасйа виш́веш́а-мӯртер
джайати джайати нр̣тйам̇
тасйа сарва-прийа̄н̣а̄м',NULL,NULL),('cb.adi.1.6','cb','cb.adi.1','ЧБ Ади 1.6',6,'আদ্যে শ্রীচৈতন্যপ্রিয়-গোষ্ঠীর চরণে ।
অশেষ-প্রকারে মোর দ-পরণামে ॥৬॥','а̄дйе ш́рӣ чаитанйа-прийа-гош̣т̣хӣра чаран̣е
аш́еш̣а-прака̄ре мора дан̣д̣а-паран̣а̄ме',NULL,NULL),('cb.adi.1.7','cb','cb.adi.1','ЧБ Ади 1.7',7,'তবে বন্দোঁশ্রীকৃষ্ণচৈতন্য মহেশ্বর ।
নবদ্বীপে অবতার, নাম—‘বিশ্বম্ভর’ ॥৭॥','табе вандон̇ ш́рӣ кр̣ш̣н̣а чаитанйа махеш́вара
навадвӣпе авата̄ра, на̄ма — ‘виш́вамбхара’',NULL,NULL),('cb.adi.1.8','cb','cb.adi.1','ЧБ Ади 1.8',8,'‘আমার ভক্তের পূজা—আমা হৈতে বড়’ ।
সেই প্রভু বেদে-ভাগবতে কৈলা দঢ় ॥৮॥','‘а̄ма̄ра бхактера пӯджа̄ — а̄ма̄’ хаите бад̣а’
сеи прабху веде-бха̄гавате каила̄ дад̣ха',NULL,NULL),('cb.adi.1.9','cb','cb.adi.1','ЧБ Ади 1.9',9,'মদ্ভক্তপূজাভ্যধিকা
সর্ব্বভূতেষু মন্মতিঃ ॥৯॥','мад-бхакта-пӯджа̄бхйадхика̄
сарва-бхӯтеш̣у ман-матих̣',NULL,NULL),('cb.adi.1.10','cb','cb.adi.1','ЧБ Ади 1.10',10,'এতেকে করিলুঁ আগে ভক্তের বন্দন ।
অতএব আছে কার্য্যসিদ্ধির লক্ষণ ॥১০॥','этеке карилун̇ а̄ге бхактера вандана
атаева а̄чхе ка̄рйа сиддхира лакш̣ан̣а',NULL,NULL),('cb.adi.1.11','cb','cb.adi.1','ЧБ Ади 1.11',11,'ইষ্টদেব বন্দোঁ মোর নিত্যানন্দ-রায় ।
চৈতন্যের কীর্ত্তি স্ফুরে যাঁহার কৃপায় ॥১১॥','иш̣т̣а-дева вандон̇ мора нитйа̄нанда-ра̄йа
чаитанйера кӣрти спхуре йа̄н̇ха̄ра кр̣па̄йа',NULL,NULL),('cb.adi.1.12','cb','cb.adi.1','ЧБ Ади 1.12',12,'সহস্রবদন বন্দোঁ প্রভু-বলরাম ।2
যাঁহার সহস্র-মুখে কৃষ্ণযশোধাম ॥১২॥','сахасра-вадана вандон̇ прабху-балара̄ма
йа̄н̇ха̄ра сахасра-мукхе кр̣ш̣н̣а-йаш́одха̄ма',NULL,NULL),('cb.adi.1.13','cb','cb.adi.1','ЧБ Ади 1.13',13,'মহারত্ন থুই যেন মহাপ্রিয়-স্থানে ।
যশোরত্ন-ভাণ্ডার শ্রীঅনন্ত-বদনে ॥১৩॥','маха̄-ратна тхуи йена маха̄прийа-стха̄не
йаш́о-ратна-бха̄н̣д̣а̄ра ш́рӣ ананта-вадане',NULL,NULL),('cb.adi.1.14','cb','cb.adi.1','ЧБ Ади 1.14',14,'অতএব আগে বলরামের স্তবন ।
করিলে সে মুখে স্ফুরে চৈতন্য-কীর্ত্তন ॥১৪॥','атаева а̄ге балара̄мера ставана
кариле се мукхе спхуре чаитанйа-кӣртана',NULL,NULL),('cb.adi.1.15','cb','cb.adi.1','ЧБ Ади 1.15',15,'সহস্রেক-ফণাধর প্রভু-বলরাম ।
যতেক করয়ে প্রভু, সকল—উদ্দাম ॥১৫॥','сахасрека-пхан̣а̄дхара прабху-балара̄ма
йатека карайе прабху, сакала — удда̄ма',NULL,NULL),('cb.adi.1.16','cb','cb.adi.1','ЧБ Ади 1.16',16,'হলধর-মহাপ্রভু প্রকা-শরীর ।
চৈতন্যচন্দ্রের যশোমত্ত মহাধীর ॥১৬॥','халадхара-маха̄прабху прака̄н̣д̣а-ш́арӣра
чаитанйа-чандрера йаш́оматта маха̄дхӣра',NULL,NULL),('cb.adi.1.17','cb','cb.adi.1','ЧБ Ади 1.17',17,'ততোধিক চৈতন্যের প্রিয় নাহি আর ।2
নিরবধি সেই দেহে করেন বিহার ॥১৭॥','татодхика чаитанйера прийа на̄хи а̄ра
ниравадхи сеи дехе карена виха̄ра',NULL,NULL),('cb.adi.1.18','cb','cb.adi.1','ЧБ Ади 1.18',18,'তাঁহার চরিত্র যেবা জনে শুনে, গায় ।
শ্রীকৃষ্ণচৈতন্য—তাঁরে পরম সহায় ॥১৮॥','та̄н̇ха̄ра чаритра йеба̄ джане ш́уне, га̄йа
ш́рӣ кр̣ш̣н̣а чаитанйа — та̄н̇ре парама саха̄йа',NULL,NULL),('cb.adi.1.19','cb','cb.adi.1','ЧБ Ади 1.19',19,'মহাপ্রীত হয় তাঁরে মহেশ-পার্ব্বতী ।
জিহ্বায় স্ফুরয়ে তাঁর শুদ্ধা সরস্বতী ॥১৯॥','маха̄прӣта хайа та̄н̇ре махеш́а-па̄рватӣ
джихва̄йа спхурайе та̄н̇ра ш́уддха̄ сарасватӣ',NULL,NULL),('cb.adi.1.20','cb','cb.adi.1','ЧБ Ади 1.20',20,'পার্ব্বতী প্রভৃতি নবার্ব্বুদ নারী লঞা ।
সঙ্কর্ষণ পূজে শিব, উপাসক হঞা ॥২০॥','па̄рватӣ-прабхр̣ти нава̄рбуда на̄рӣ лан̃а̄
сан̇карш̣ан̣а пӯдже ш́ива, упа̄сака хан̃а̄',NULL,NULL),('cb.adi.1.21','cb','cb.adi.1','ЧБ Ади 1.21',21,'পঞ্চম-স্কন্ধের এই ভাগবত-কথা ।
সর্ব্ববৈষ্ণবের বন্দ্য বলরাম-গাথা ॥২১॥','пан̃чама-скандера эи бха̄гавата-катха̄
сарва ваиш̣н̣авера вандйа балара̄ма-га̄тха̄',NULL,NULL),('cb.adi.1.22','cb','cb.adi.1','ЧБ Ади 1.22',22,'তান রাসক্রীড়া-কথা—পরম উদার ।
বৃন্দাবনে গোপী-সনে করিলা বিহার ॥২২॥','та̄на ра̄са-крӣд̣а̄-катха̄ — парама уда̄ра
вр̣нда̄ване гопӣ-сане карила̄ виха̄ра',NULL,NULL),('cb.adi.1.23','cb','cb.adi.1','ЧБ Ади 1.23',23,'দুইমাস বসন্ত, মাধব-মধু-নামে ।
হলায়ুধ-রাসক্রীড়া কহয়ে পুরাণে ॥২৩॥','дуи-ма̄са васанта, ма̄дхава-мадху-на̄ме
хала̄йудха-ра̄са-крӣд̣а̄ кахайе пура̄н̣е',NULL,NULL),('cb.adi.1.24','cb','cb.adi.1','ЧБ Ади 1.24',24,'সে সকল শ্লোক এই শুন ভাগবতে ।
শ্রীশুক কহেন, শুনে রাজা-পরীক্ষিতে ॥২৪॥','се сакала ш́лока эи ш́уна бха̄гавате
ш́рӣ ш́ука кахена, ш́уне ра̄джа̄-парӣкш̣ите',NULL,NULL),('cb.adi.1.25','cb','cb.adi.1','ЧБ Ади 1.25',25,'দ্বৌ মাসৌ তত্র চাবাৎসীন্মধুং মাধবমেব চ ।
রামঃ ক্ষপাসু ভগবান্ গোপীনাং রতিমাবহন্ ॥২৫॥','двау ма̄сау татра ча̄ва̄тсӣн
мадхум̇ ма̄дхавам эва ча
ра̄мах̣ кш̣апа̄су бхагава̄н
гопӣна̄м̇ ратим а̄вахан',NULL,NULL),('cb.adi.1.26','cb','cb.adi.1','ЧБ Ади 1.26',26,'পূর্ণচন্দ্রকলামৃষ্টে কৌমুদীগন্ধবায়ুনা ।
যমুনোপবনে রেমে সেবিতে স্ত্রীগণৈর্বৃতঃ ॥২৬॥','пӯрн̣а-чандра-кала̄-мр̣ш̣т̣е
каумудӣ-гандха-ва̄йуна̄
стрӣ-ган̣аир вр̣тах̣',NULL,NULL),('cb.adi.1.29','cb','cb.adi.1','ЧБ Ади 1.29',29,'যে স্ত্রীসঙ্গ মুনিগণে করেন নিন্দন ।
তাঁরাও রামের রাসে করেন স্তবন ॥২৯॥','йе стрӣ-сан̇га муни-ган̣е карена ниндана
та̄н̇ра̄о ра̄мера ра̄се карена ставана',NULL,NULL),('cb.adi.1.30','cb','cb.adi.1','ЧБ Ади 1.30',30,'যাঁর রাসে দেবে আসি’ পুষ্পবৃষ্টি করে ।
দেবে জানে,—ভেদ নাহি কৃষ্ণ-হলধরে ॥৩০॥','йа̄н̇ра ра̄се деве а̄си’ пуш̣па-вр̣ш̣т̣и каре
деве джа̄не, — бхеда на̄хи кр̣ш̣н̣а-халадхаре',NULL,NULL),('cb.adi.1.31','cb','cb.adi.1','ЧБ Ади 1.31',31,'চারি-বেদে গুপ্ত বলরামের চরিত ।
আমি কি বলিব, সব—পুরাণে বিদিত ॥৩১॥','ча̄ри-веде гупта балара̄мера чарита
а̄ми ки балиба, саба — пура̄н̣е видита',NULL,NULL),('cb.adi.1.32','cb','cb.adi.1','ЧБ Ади 1.32',32,'মূর্খ-দোষে কেহ কেহ না দেখি’ পুরাণ ।
বলরাম-রাসক্রীড়া করে অপ্রমাণ ॥৩২॥','мӯркха-дош̣е кеха кеха на̄ декхи’ пура̄н̣а
балара̄ма-ра̄са-крӣд̣а̄ каре апрама̄н̣а',NULL,NULL),('cb.adi.1.33','cb','cb.adi.1','ЧБ Ади 1.33',33,'একঠাঁই দুইভাই গোপিকা-সমাজে ।
করিলেন রাসক্রীড়া বৃন্দাবন-মাঝে ॥৩৩॥','эка т̣ха̄н̃и дуи-бха̄и гопика̄-сама̄дже
карилена ра̄са-крӣд̣а̄ вр̣нда̄вана-ма̄джхе',NULL,NULL),('cb.adi.1.34','cb','cb.adi.1','ЧБ Ади 1.34',34,'কদাচিদথ গোবিন্দো রামশ্চাদ্ভুতবিক্রমঃ ।
বিজহ্রতুর্ব্বনে রাত্র্যাং মধ্যগৌ ব্রজযোষিতাম্ ॥৩৪॥','када̄чид атха говиндо
ра̄маш́ ча̄дбхута-викрамах̣
виджахратур ване ра̄трйа̄м̇
мадхйа-гау враджа-йош̣ита̄м',NULL,NULL),('cb.adi.1.35','cb','cb.adi.1','ЧБ Ади 1.35',35,'উপগীয়মানৌ ললিতং স্ত্রীরত্নৈর্ব্বদ্ধসৌহৃদৈঃ ।
স্বলঙ্কৃতানুলিপ্তাঙ্গৌ স্রগ্বিণৌ বিরজোঽম্বরৌ ॥৩৫॥','упагӣйама̄нау лалитам̇
стрӣ-ратнаир баддха-саухр̣даих̣
св-алан̇кр̣та̄нулипта̄н̇гау
срагвин̣ау вираджо-’мбарау',NULL,NULL),('cb.adi.1.36','cb','cb.adi.1','ЧБ Ади 1.36',36,'নিশামুখং মানয়ন্তাবুদিতোড়ুপ-তারকম্ ।
মল্লিকাগন্ধ-মত্তালি-জুষ্টং কুমুদবায়ুনা ॥৩৬॥','ниш́а-мукхам̇ ма̄найанта̄в
удитод̣упа-та̄ракам
маллика̄-гандха-матта̄ли-
джуш̣т̣ам̇ кумуда-ва̄йуна̄',NULL,NULL),('cb.adi.1.37','cb','cb.adi.1','ЧБ Ади 1.37',37,'জগতুঃ সর্ব্বভূতানাং মনঃশ্রবণমঙ্গলম্ ।
তৌ কল্পয়ন্তৌ যুগপৎ স্বরমণ্ডলমূর্চ্ছিতম্ ॥৩৭॥','джагатух̣ сарва-бхӯта̄на̄м̇
манах̣-ш́раван̣а-ман̇галам
